import { useEffect, useState } from "react";
import { getUsers, deleteUser } from "../api/api";
import UserForm from "../components/UserForm";
import "./Home.css";
import { useNavigate } from "react-router-dom";
import { useLocation } from "react-router-dom";

export default function Home({ setIsLoggedIn }) {
  const [users, setUsers] = useState([]);
  const navigate = useNavigate();
  const location = useLocation();
  const editUser = location.state;

  useEffect(() => {
    loadUsers();
  }, []);

  useEffect(() => {
  const token = localStorage.getItem("token");

 
}, []);

  const loadUsers = async () => {
    const data = await getUsers();
    

    if (data.detail === "Invalid token") {
    localStorage.removeItem("token");
    setIsLoggedIn(false);
    navigate("/");
  } else {
    setUsers(data);
  }
  };

  const handleDelete = async (id) => {
    await deleteUser(id);
    loadUsers();
  };

  const handleLogout = () => {
  localStorage.removeItem("token");
  setIsLoggedIn(false);    
  navigate("/");      
  };

  const [editingUser, setEditingUser] = useState(null);

  return (
    
    <div className="container">
      <h2 className="title">USER PAGE</h2>

      <button onClick={handleLogout} className="logout_btn" >Logout</button>

      <UserForm reload={loadUsers}
                editingUser={editingUser}
                setEditingUser={setEditingUser} />
       <br/><h3 style={{fontFamily: "serif", fontWeight: "bold"}}>Existing users :</h3>

      <div style={{ marginTop: "20px" }}>
        
            <button onClick={() => navigate("/users")}>
                Show Existing Users
            </button>
          </div>
          </div>
        )};

      
  











